function.body:
-- Logistice v_ResultStr VARCHAR2(2000):=''; v_Message VARCHAR2(2000):=''; v_Result NUMBER:=1; -- 0=failure v_Record_ID VARCHAR2(32); v_User_ID VARCHAR2(32):='0';
TYPE RECORD IS REF CURSOR; Cur_Parameter RECORD; vOrderLine RECORD; vInOutLine RECORD; vInvoiceLine RECORD;
BEGIN
DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || P_Instance_ID); v_ResultStr:='PInstanceNotFound'; AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'Y', NULL, NULL);
BEGIN --BODY -- Get Parameters v_ResultStr:='ReadingParameters'; FOR Cur_Parameter IN ( SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String, p.P_Number, p.P_Date FROM AD_PInstance i LEFT JOIN AD_PInstance_Para p ON i.AD_PInstance_ID = p.AD_PInstance_ID WHERE i.AD_PInstance_ID = P_Instance_ID ORDER BY p.SeqNo ) LOOP v_Record_ID := Cur_Parameter.Record_ID; v_User_ID := Cur_Parameter.AD_User_ID; END LOOP; -- Get Parameter
--insertar lineas vOrderLine ----------------------
FOR vOrderLine IN ( SELECT DISTINCT co.ad_client_id, co.ad_org_id, co.updatedby, co.updatedby, ol.c_orderline_id, iol.m_inoutline_id, il.c_invoiceline_id, ol.m_product_id, ol.qtyordered FROM c_orderline ol LEFT JOIN c_invoiceline il ON il.c_orderline_id = ol.c_orderline_id LEFT JOIN c_order co ON co.c_order_id = ol.c_order_id LEFT JOIN m_inoutline iol ON iol.c_orderline_id = ol.c_orderline_id LEFT JOIN sinvmin_square_bill sb ON sb.c_orderline_id = ol.c_orderline_id AND ad_table_id = '259' WHERE sb.sinvmin_square_bill_id IS NULL AND co.issotrx = 'Y' AND co.DocStatus = 'CO' AND sb.c_orderline_id IS NULL ) LOOP INSERT INTO sinvmin_square_bill ( sinvmin_square_bill_id, ad_client_id, ad_org_id, createdby, updatedby, c_orderline_id, m_inoutline_id, c_invoiceline_id, m_product_id, qty, datetrx, ad_table_id ) VALUES ( get_uuid(), vOrderLine.ad_client_id, vOrderLine.ad_org_id, vOrderLine.updatedby, vOrderLine.updatedby, vOrderLine.c_orderline_id, null,--vOrderLine.m_inoutline_id, null,--vOrderLine.c_invoiceline_id, vOrderLine.m_product_id, vOrderLine.qtyordered, TO_DATE(now()), '259' -- C_Order ); END LOOP;
--insertar lineas de vInOutLine ----------------------
FOR vInOutLine IN ( SELECT io.ad_client_id, io.ad_org_id, io.updatedby, io.updatedby, iol.line, ol.c_orderline_id, iol.m_inoutline_id, il.c_invoiceline_id, iol.m_product_id, iol.movementqty, sb.qty FROM m_inoutline iol LEFT JOIN m_inout io ON io.m_inout_id = iol.m_inout_id LEFT JOIN c_orderline ol ON ol.c_orderline_id = iol.c_orderline_id LEFT JOIN sinvmin_square_bill sq ON sq.m_inoutline_id = iol.m_inoutline_id LEFT JOIN c_invoiceline il ON il.m_product_id = iol.m_product_id AND il.c_invoice_id = io.c_invoice_id AND iol.isinvoiced = 'Y' AND (il.c_orderline_id = iol.c_orderline_id OR il.m_inoutline_id = iol.m_inoutline_id) LEFT JOIN ( SELECT il.c_invoiceline_id, il.qtyinvoiced - COALESCE(ABS(iol.movementqty),0) qty,sb.sinvmin_square_bill_id FROM c_invoiceline il JOIN sinvmin_square_bill sb ON sb.c_invoiceline_id = il.c_invoiceline_id LEFT JOIN ( SELECT c_invoiceline_id, SUM(qty) movementqty FROM sinvmin_square_bill WHERE ad_table_id = '319' AND c_invoiceline_id IS NOT NULL GROUP BY c_invoiceline_id ) iol ON iol.c_invoiceline_id = il.c_invoiceline_id WHERE sb.ad_table_id = '318' ) sb ON sb.c_invoiceline_id = il.c_invoiceline_id WHERE io.issotrx = 'Y' AND io.DocStatus = 'CO' and sq.m_inoutline_id is null ) LOOP /* IF vInOutLine.c_invoiceline_id IS NOT NULL AND vInOutLine.movementqty > vInOutLine.qty THEN RAISE EXCEPTION '%', 'La cantidad movida ('||vInOutLine.movementqty||') de la línea '||vInOutLine.line ||' supera la candidad pendiente por facturar ('||vInOutLine.qty||')'; --OBTG:-20000-- END IF; */ INSERT INTO sinvmin_square_bill ( sinvmin_square_bill_id, ad_client_id, ad_org_id, createdby, updatedby, c_orderline_id, m_inoutline_id, c_invoiceline_id, m_product_id, qty, datetrx, ad_table_id ) VALUES ( get_uuid(), vInOutLine.ad_client_id, vInOutLine.ad_org_id, vInOutLine.updatedby, vInOutLine.updatedby, vInOutLine.c_orderline_id, vInOutLine.m_inoutline_id, null,--vInOutLine.c_invoiceline_id, vInOutLine.m_product_id, vInOutLine.movementqty * -1, TO_DATE(now()), '319' -- M_InOut ); END LOOP;
--insertar lineas de vInvoiceLine ---------------------
FOR vInvoiceLine IN ( SELECT il.ad_client_id,il.ad_org_id,il.updatedby,il.updatedby, il.line, ol.c_orderline_id, im.m_inoutline_id, il.c_invoiceline_id, il.m_product_id, il.qtyinvoiced, im.qty FROM c_invoiceline il LEFT JOIN c_orderline ol ON ol.c_orderline_id = il.c_orderline_id LEFT JOIN sinvmin_square_bill sb ON sb.c_invoiceline_id = il.c_invoiceline_id AND ad_table_id = '318' LEFT JOIN c_invoice ci on ci.c_invoice_id=il.c_invoice_id LEFT JOIN ( SELECT iol.m_inoutline_id, iol.movementqty - COALESCE(ABS(il.qtyinvoiced),0) qty FROM m_inoutline iol JOIN sinvmin_square_bill sb ON sb.m_inoutline_id = iol.m_inoutline_id LEFT JOIN ( SELECT m_inoutline_id, SUM(qty) qtyinvoiced FROM sinvmin_square_bill WHERE (ad_table_id = '318' AND m_inoutline_id IS NOT NULL) OR (ad_table_id = '319' AND c_invoiceline_id IS NOT NULL) GROUP BY m_inoutline_id ) il ON il.m_inoutline_id = iol.m_inoutline_id WHERE sb.ad_table_id = '319' ) im ON im.m_inoutline_id = il.m_inoutline_id where ci.issotrx='Y' and ci.docstatus='CO' and sb.c_invoiceline_id IS NULL
) LOOP DBMS_OUTPUT.PUT_LINE(vInvoiceLine.c_orderline_id);
INSERT INTO sinvmin_square_bill ( sinvmin_square_bill_id, ad_client_id, ad_org_id, createdby, updatedby, c_orderline_id, m_inoutline_id, c_invoiceline_id, m_product_id, qty, datetrx, ad_table_id ) VALUES ( get_uuid(), vInvoiceLine.ad_client_id, vInvoiceLine.ad_org_id, vInvoiceLine.updatedby, vInvoiceLine.updatedby, vInvoiceLine.c_orderline_id, vInvoiceLine.m_inoutline_id, vInvoiceLine.c_invoiceline_id, vInvoiceLine.m_product_id, vInvoiceLine.qtyinvoiced, TO_DATE(now()), '318' -- C_Invoice ); END LOOP;
RETURN; END; --BODY EXCEPTION WHEN OTHERS THEN v_ResultStr:= '@ERROR=' || SQLERRM; DBMS_OUTPUT.PUT_LINE( v_ResultStr) ; ROLLBACK; AD_UPDATE_PINSTANCE(p_instance_id, NULL, 'N', 0, v_ResultStr); END SIS_SQUAREBILL_INSERT
